/**
 * @generated by @flusk/cli
 * CLI command: flusk conversations-top
 */
import { Command } from 'commander';
import chalk from 'chalk';
import { createSqliteStorage } from '@flusk/resources';

export const conversationsTopCommand = new Command('conversations-top')
  .description('Show top conversations by cost, turns, or tokens')
  .option('-b, --by <metric>', 'Sort by: cost|turns|tokens', 'cost')
  .option('-l, --limit <n>', 'Number of results', '10')
  .action((opts) => {
    const storage = createSqliteStorage();
    const metric = opts.by as 'cost' | 'turns' | 'tokens';
    const fetchers = {
      cost: () => storage.conversations.topByCost(),
      turns: () => storage.conversations.topByTurns(),
      tokens: () => storage.conversations.topByTokens(),
    };

    const rows = fetchers[metric]();

    if (rows.length === 0) {
      console.log(chalk.dim('No conversations found.'));
      return;
    }

    console.log(chalk.bold(`Top conversations by ${metric}:\n`));
    const header = [
      pad('#', 4), pad('ID', 10), pad('Provider', 12),
      pad('Model', 20), pad('Turns', 6), pad('Cost', 10), 'Tokens',
    ].join('  ');

    console.log(chalk.bold(header));
    console.log(chalk.dim('─'.repeat(85)));

    for (let i = 0; i < Math.min(rows.length, parseInt(opts.limit, 10)); i++) {
      const r = rows[i] as Record<string, unknown>;
      const row = [
        pad(String(i + 1), 4),
        pad(String(r.id ?? '').slice(0, 8), 10),
        pad(String(r.provider ?? ''), 12),
        pad(String(r.model ?? ''), 20),
        pad(String(r.turn_count ?? 0), 6),
        pad(`$${Number(r.total_cost ?? 0).toFixed(4)}`, 10),
        String(Number(r.total_input_tokens ?? 0) + Number(r.total_output_tokens ?? 0)),
      ].join('  ');
      console.log(row);
    }
  });

function pad(s: string, len: number): string {
  return s.length >= len ? s.slice(0, len) : s + ' '.repeat(len - s.length);
}
